import { fromStore, toStore, writable } from 'svelte/store';
export const useCursor = (onPointerOver = 'pointer', onPointerOut = 'auto', target = undefined) => {
    let hovering = $state(false);
    const onPointerEnter = () => {
        hovering = true;
    };
    const onPointerLeave = () => {
        hovering = false;
    };
    // Account for SSR use
    if (typeof window === 'undefined') {
        return {
            hovering: toStore(() => hovering),
            onPointerEnter,
            onPointerLeave
        };
    }
    const pointerOver = fromStore(typeof onPointerOver === 'string' ? writable(onPointerOver) : onPointerOver);
    const pointerOut = fromStore(typeof onPointerOut === 'string' ? writable(onPointerOut) : onPointerOut);
    const el = target ?? document.body;
    const originalCursor = el.style.cursor;
    $effect.pre(() => {
        if (hovering) {
            el.style.cursor = pointerOver.current;
        }
        else {
            el.style.cursor = pointerOut.current;
        }
    });
    // Reset the cursor style
    $effect(() => {
        return () => {
            el.style.cursor = originalCursor;
        };
    });
    return {
        hovering: toStore(() => hovering),
        onPointerEnter,
        onPointerLeave
    };
};
